SUNSH81244BER5080_HiRes.jpg\"},{\"DesignID\":\"81247\",\"Description\":\"LR81247\",\"ImageName\":\"images\\/Product\\/1594996448SUNSH81247BGR5080_HiRes.jpg\"},{\"DesignID\":\"81248\",\"Description\":\"LR81248\",\"ImageName\":\"images\\/Product\\/1594996453SUNSH81248BGR5080_HiRes.jpg\"},{\"DesignID\":\"81249\",\"Description\":\"LR81249\",\"ImageName\":\"images\\/Product\\/1618308790SUNSH81249NVG5080_HiRes_1.jpg\"},{\"DesignID\":\"81246\",\"Description\":\"LR81246\",\"ImageName\":\"images\\/Product\\/1594996443SUNSH81246GYB5080_HiRes.jpg\"},{\"DesignID\":\"81250\",\"Description\":\"LR81250\",\"ImageName\":\"images\\/Product\\/1608613337SUNSH81250TLB3050_HiRes.jpg\"}]},\"description\":\"Our Sun Shower Collection is full of ornate and tasteful geometric designs. \\u00a0Adding one of these rugs to your indoor or outdoor space is sure to thrill you and your guests. The flat weave design makes this rug perfect for high traffic areas or even some sandy patios, as this piece is easily shaken out. Don\'t overlook the endless opportunities this indoor\\/outdoor collection has to offer for a variety of different spaces in your home.\",\"image\":\"http:\\/\\/lrhome.us\\/images\\/Product\\/1618308790SUNSH81249NVG5080_HiRes_1.jpg\"},\"Captiva\":{\"title\":\"Captiva\",\"raw\":{\"CollectionID\":\"Captiva\",\"Description\":\"Captiva\",\"ImageName\":\"images\\/Product\\/1594326636CAPTI81021GBU5070_Web.jpg\",\"NewArrivalExpiry\":\"False\",\"Clearence\":\"\",\"TopSeller\":\"False\",\"SpecialBuy\":\"\",\"DesignsList\":[{\"DesignID\":\"81016\",\"Description\":\"LR81016\",\"ImageName\":\"images\\/Product\\/1594324299CAPTI81016BEL5070_Web.jpg\"},{\"DesignID\":\"81017\",\"Description\":\"LR81017\",\"ImageName\":\"images\\/Product\\/1594324274CAPTI81017NVG5070_Web.jpg\"},{\"DesignID\":\"81019\",\"Description\":\"LR81019\",\"ImageName\":\"images\\/Product\\/1594325498CAPTI81019GNY5070_Web.jpg\"},{\"DesignID\":\"81020\",\"Description\":\"LR81020\",\"ImageName\":\"images\\/Product\\/1594325472CAPTI81020CBG5070_Web.jpg\"},{\"DesignID\":\"81021\",\"Description\":\"LR81021\",\"ImageName\":\"images\\/Product\\/1594326636CAPTI81021GBU5070_Web.jpg\"},{\"DesignID\":\"81022\",\"Description\":\"LR81022\",\"ImageName\":\"images\\/Product\\/1594326603CAPTI81022BGR5070_Web.jpg\"},{\"DesignID\":\"81023\",\"Description\":\"LR81023\",\"ImageName\":\"images\\/Product\\/1594326367CAPTI81023REE5070_Web.jpg\"},{\"DesignID\":\"81024\",\"Description\":\"LR81024\",\"ImageName\":\"images\\/Product\\/1594326307CAPTI81024BEP5070_Web.jpg\"},{\"DesignID\":\"81025\",\"Description\":\"LR81025\",\"ImageName\":\"images\\/Product\\/1594326254CAPTI81025NVG5070_Web.jpg\"}]},\"description\":\"This collection is sure to catch your eye with beautiful colors and the variety of coastal designs. The indoor\\/outdoor flexibility of this collection makes it a great addition to a patio area, living room, or even sunroom. The flat weave design makes this rug perfect for high traffic areas or even some sandy patios, as this piece is easily shaken out. Don\'t overlook the endless opportunities this indoor\\/outdoor collection has to offer for a variety of different spaces in your home.\",\"image\":\"http:\\/\\/lrhome.us\\/images\\/Product\\/1594326922CAPTI81018REE5070_Web.jpg\"},\"Seaside\":{\"title\":\"Seaside\",\"raw\":{\"CollectionID\":\"Seaside\",\"Description\":\"Seaside\",\"ImageName\":\"images\\/Product\\/1601565886SEADE81879AQT5370_HiRes.jpg\",\"NewArrivalExpiry\":\"True\",\"Clearence\":\"\",\"TopSeller\":\"False\",\"SpecialBuy\":\"\",\"DesignsList\":[{\"DesignID\":\"81871\",\"Description\":\"LR81871\",\"ImageName\":\"images\\/Product\\/1601506508SEADE81871AWT5370_HiRes.jpg\"},{\"DesignID\":\"81872\",\"Description\":\"LR81872\",\"ImageName\":\"images\\/Product\\/1601506852SEADE81872AWT5370_HiRes.jpg\"},{\"DesignID\":\"81873\",\"Description\":\"LR81873\",\"ImageName\":\"images\\/Product\\/1601506883SEADE81873WAZ5370_HiRes.jpg\"},{\"DesignID\":\"81874\",\"Description\":\"LR81874\",\"ImageName\":