(38, 1, '{\"_token\":\"QxpBpPPboYan2KFA3th2si92hy0Bk4dLyvUqBbrK\",\"name\":\"Andy Sun\",\"subject\":\"Polyester staple fiber\",\"email\":\"fen.chen@smlon.com\",\"phone\":\"+88637584735\",\"company\":\"SHING MING IND. CO., LTD.\",\"city\":\"Miaoli\",\"state\":\"Taiwan\",\"message\":\"Dear Sir,\\r\\nNice to know you. \\r\\nWe are Shing Ming industrial company in Taiwan, a fiber manufacturer produces POLYESTER STAPLE FIBER.\\r\\nPlease kindly let me know if you have demand on our product.\\r\\n\\r\\nFollowing is our product list: Polyester Staple Fiber solid, Regenerated.\\r\\n1) Denier : 6D ~ 20 D\\r\\n2) Cut length : 32MM ~ 110MM\\r\\n3) Luster : Raw white\\r\\n4) Silicon, Slick and Non-silicon\\r\\n5) MOQ:9T\\r\\n6) Weight: about 250 -300kg \\/bale\\r\\n7) Production Capacity: 1500MT \\/monthly\\r\\n8) Payment term: T\\/T or LC at sight\\r\\n\\r\\nLook forward to your reply and hopefully we can work together for win-win business. \\r\\nSincerely yours, \\r\\nAndy Sun \\r\\nShing Ming Ind Co Ltd. \\r\\nMail: fen.chen@smlon.com \\r\\nTel: 037-584735\\r\\nSHING MING IND. CO., LTD.\\r\\nhttps:\\/\\/www.smlon.com\"}', '2022-11-01 14:52:25', '2022-11-01 14:52:25', NULL),
(39, 1, '{\"_token\":\"eKlunm4vwyF2FhEgpLrh7kg74PMcEJqP01LDQZzk\",\"name\":\"Andrew\",\"subject\":\"Drop-ship cooperation\",\"email\":\"hyggecave@gmail.com\",\"phone\":\"3109208017\",\"company\":\"Hygge Cave\",\"city\":\"Los Angeles\",\"state\":\"California\",\"message\":\"Good morning, my name Andrew Fateev (Hygge Cave), we have previously talked to Mattew White about the onboarding process as a dropshipping company back on August 20ths. Haven\'t gotten a response from him, we still would love to add your beautiful products to our catalog, and would like to know if there are any updates with our process. Thank you in advance.\"}', '2022-11-01 21:55:40', '2022-11-01 21:55:40', NULL),
(40, 1, '{\"_token\":\"e9Q4sI9y3QiiB3M85dqefMl9ONphnmiKLqaF7Gi9\",\"name\":\"Alex Wood\",\"subject\":\"Get A Wikipedia Page For Yourself Or For Your Company.\",\"email\":\"alexw@elite-wikiwriters.com\",\"phone\":\"13\",\"company\":\"Elite Wiki Writers\",\"city\":\"Los Angeles\",\"state\":\"CA\",\"message\":\"Wikipedia is considered to be the World\\u2019s most significant tool for reference material. The Wiki links show up on the 1st page of Google 97% of the time. With a Page on one of the most revered reference tools, you are sure to get yourself or your business noticed. So if you\'re thinking of getting a Wikipedia Page created, it\'s the best time of the year.\\r\\n\\r\\nIf you are interested in getting more information just respond back to this email.\\r\\n\\r\\nThanks,\\r\\n\\r\\nAlex Wood\\r\\n(866) 292-9696\\r\\nElite Wiki Writers\\r\\nalexw@elite-wikiwriters.com\\r\\n\\r\\nRespond with stop to optout.\"}', '2022-11-02 00:31:09', '2022-11-02 00:31:09', NULL),
