(94, 1, '{\"_token\":\"ucTqVI1YkhwxAYAOR37iEcpCx0a9WcpJQTEr6UeN\",\"name\":\"Ashley Diehl\",\"subject\":\"Trade Account\",\"email\":\"ashley@ingrainhomedesign.com\",\"phone\":\"5605035336\",\"company\":\"Ingrain Home Design\",\"city\":\"West Linn\",\"state\":\"Oregon\",\"message\":\"Hello,\\r\\nI just wanted to follow up on my Trade application.  I met with Tim Brown at High Point, who was lovely and took great time showing me and my travel partner around the showroom.  I filled out the trade application about 3-4 weeks ago and didn\'t hear back. Today I tried again but wanted to make sure and create this second touch point in case my application isn\'t reaching the correct desk.  \\r\\n\\r\\nI\'d love to know how to access your product for my clients. I have one of your throws in a project I\'m hoping to sell through next week.\\r\\n\\r\\nThank you!\\r\\n\\r\\nAshley Diehl\"}', '2022-12-03 02:03:02', '2022-12-03 02:03:02', NULL),
