(98, 1, '{\"_token\":\"m3vTNGZti1FSUJLpL79As05S4amylWNLekVboV4A\",\"name\":\"Mackenzie Talbert\",\"subject\":\"Tiger Pillow\",\"email\":\"mackenzie@studio5interior.com\",\"phone\":\"7703600090\",\"company\":\"Studio 5 Interiors\",\"city\":\"Alpharetta\",\"state\":\"Georgia\",\"message\":\"In your showroom at Highpoint this year I saw a pillow with a tiger face but I can\'t seem to find it on your website, can someone point to out to me\"}', '2022-12-06 22:15:22', '2022-12-06 22:15:22', NULL),
(99, 1, '{\"_token\":\"ZyqK5i6T8fqAv2mEpi76l3d2Llvrp3XG8ccLPbCZ\",\"name\":\"Tasneem\",\"subject\":\"Carpet since 1975\",\"email\":\"tasneembhadohi@gmail.com\",\"phone\":\"9839164766\",\"company\":\"Oriental Matting Corporation\",\"city\":\"Bhadohi\",\"state\":\"Uttar Pardesh\",\"message\":\"Dear Sirs,\\r\\nOriental Matting Corporation is manufacturer and Exporter of Dari and Carpet Since 1975 and the founder was Late Zahir Alam,Quazipur,Bhadohi,India.\\r\\nHe was also introduce Flat weave rugs to India.\\r\\nwe have very good collection of hand loom carpet,flat weave and hand knotted carpet in semi worsted wool,jute and polyester,Cushion Covers,Puff,Home decor.\\r\\nHope you will give us a chance to show you my  collection presentation ppt. \\r\\nIf you have representative in India please let me know his contact number to contact him.\\r\\nI have lot of hope from you to full fill my dreams.\\r\\nKind regards,\\r\\n\\r\\n\\r\\nOriental Matting Corporation\\r\\nTasneem Alam Ansari\\r\\nCEO | Oriental Matting Corporation\\r\\nT  +91 9839164766     tasneembhadohi@gmail.com\\r\\n  quazipur, Bhadohi, Uttar Pradesh, India\"}', '2022-12-09 22:22:04', '2022-12-09 22:22:04', NULL),
(100, 1, '{\"_token\":\"g0v7pAE9IrYFEaHULgoNvi2yZUpaqmyvgDN6Lwh5\",\"name\":\"Raj Kumar\",\"subject\":\"New business proposal\",\"email\":\"rk@livingart-crafts.com\",\"phone\":\"9009720003\",\"company\":\"Living Art & Crafts\",\"city\":\"Jodhpur\",\"state\":\"Rajasthan\",\"message\":\"Hi there,\\r\\nI Raj kumar as Export manager in M\\/s Living Art & Interior at Jodhpur,Rajasthan(India).We are leading manufacturing,Exporter and Supplier of wooden furniture and supply bulk order to top exporter in India and also dealing with outside India.\\r\\nWe have wide range of wooden furniture and we are used some combination of furniture with best price and quality.\\r\\nWe will happy if you reply to us and share your import department contact for further discussion.\\r\\nAwaiting your reply.\"}', '2022-12-11 00:07:37', '2022-12-11 00:07:37', NULL);
