(103, 1, '{\"_token\":\"kRpOt8LTklXjdDldaakv36avDjtai1uW0OeqX0Wa\",\"name\":\"Joji Jacob\",\"subject\":\"Price offer from India\",\"email\":\"joji.jacob@lordsexports.in\",\"phone\":\"9400235262\",\"company\":\"Lords Exports\",\"city\":\"Cherthala\",\"state\":\"Kerala\",\"message\":\"Dear Sir \\/ Madam,\\r\\n           We are the leading manufacture and exporters of Coir mats, Rubber mats, Polypropylene mats, Vinyl backed coir mats etc. we can offer you very good quality with reasonable price and timely delivery.\\r\\nWe are very much interested to join as a vendor on your Organization. \\r\\nIf you are interested   Pls   contact  joji.jacob@lordsexports.in or +91 9400235262. \\r\\nOur web site: www.lordsexports.in\\r\\nJOJI JACOB (proprietor) \\r\\nLORDS EXPORTS\\r\\nCMC 3\\/79H MADAKKAN\\u2019S BUILDINGS\\r\\nNORTH OF MANORAMA JUNCTION \\r\\nCHERTHALA 688524\\r\\nKERALA, INDIA\"}', '2022-12-13 15:30:35', '2022-12-13 15:30:35', NULL),
